def solve(grid):
    H, W = len(grid), len(grid[0])
    out = [[0]*(W*2) for _ in range(H*2)]
    for r in range(H):
        for c in range(W):
            if grid[r][c] != 0:
                # Place 4x4 block at (r*2-2, c*2-2)
                tr, tc = r*2-2, c*2-2
                for dr in range(4):
                    for dc in range(4):
                        rr, cc = tr+dr, tc+dc
                        if 0 <= rr < H*2 and 0 <= cc < W*2:
                            out[rr][cc] = grid[r][c]
    return out

